#include <bits/stdc++.h>
using namespace std;
const int INF=0x7F7F7F7F;
string s;
int n,len;
int dp[41][100005],num[41][41];
int main(){
	cin>>s;
	scanf("%d",&n);
	len=s.size(),s=" "+s;
	for(int i=1;i<=len;i++)
		for(int j=1;j<=i;j++)
			num[j][i]=(num[j][i-1]>n?INF:num[j][i-1]*10+s[i]-'0');
	memset(dp,127,sizeof(dp));
	dp[0][0]=-1;
	for(int i=1;i<=len;i++){
		for(int j=0;j<=n;j++){
			for(int k=i-1;k>=0 && num[k+1][i]<=n;k--)
			    if(j>=num[k+1][i])
				    dp[i][j]=min(dp[i][j],1+dp[k][j-num[k+1][i]]);
			//printf("%d ",(dp[i][j]==INF?-1:dp[i][j]));
		}
		//printf("\n");
	}
	if(dp[len][n]>=50)
		printf("-1");
	else
		printf("%lld",dp[len][n]);
	return 0;
}
